@app.middleware("http")
async def global_readonly_lock(request: Request, call_next):
    """
    法典 3.2.4: UPS 熔断大闸。
    如果 Redis 能力矩阵探针汇报 UPS=LOW_BATTERY_SHUTDOWN，
    则全局拒绝所有 POST/PUT/DELETE/PATCH 写入请求（转入只读模式）。
    """
    if request.method in ("POST", "PUT", "DELETE", "PATCH"):
        # 我们优先读 _lru_cache 以避免每次写入都拉取 Redis
        matrix = _lru_cache.get("matrix")
        
        # 如果缓存为空，说明刚启动或者被清空，主动拉取一次兜底
        if matrix is None:
            # 由于不能直接在 middleware 轻易注入依赖，我们手写轻量获取
            try:
                r = await _get_redis()
                if r:
                    val = await r.get("zen70:topology:ups")
                    await r.aclose()
                    if val and val.strip().upper() == "LOW_BATTERY_SHUTDOWN":
                         return JSONResponse(
                             status_code=503,
                             content=ErrorResponse(
                                 code="ZEN-SYS-9999",
                                 message="市电中断且电池告警，系统已进入全局强制只读模式保护硬件",
                                 recovery_hint="等待市电恢复后，网关将自动解除锁定放行写入",
                                 details={
                                     "method": request.method, 
                                     "url": str(request.url),
                                     "trace_id": getattr(request.state, "trace_id", "unknown")
                                 },
                             ).model_dump()
                         )
            except Exception:
                pass
        else:
            ups_cap = matrix.get("ups")
            if ups_cap and ups_cap.status.lower() == "low-battery-shutdown":
                return JSONResponse(
                    status_code=503,
                    content=ErrorResponse(
                        code="ZEN-SYS-9999",
                        message="市电中断且电池告警，系统已进入全局强制只读模式保护硬件",
                        recovery_hint="等待市电恢复后，网关将自动解除锁定放行写入",
                        details={
                            "method": request.method, 
                            "url": str(request.url),
                            "trace_id": getattr(request.state, "trace_id", "unknown")
                        },
                    ).model_dump()
                )
            
    # 如果正常，或者只是 GET 请求，继续 Readiness 拦截
    # Readiness 拦截保护: 服务没有跑完模型加载等初始流程前，禁止流量切入 (这里用 path 前缀简单模拟路由隔离)
    path_str = str(request.url.path)
    for svc_name, is_ready in service_readiness.items():
        if not is_ready:
            # 判断此请求是否属于该瘫痪子服务 (这里简单的用名字包含路径来模拟微服务拆分)
            if svc_name in path_str:
                return JSONResponse(
                    status_code=503,
                    content=ErrorResponse(
                        code="ZEN-SVC-NOTREADY",
                        message=f"子服务 {svc_name} 尚未就绪 (Readiness Probe 失败), 流量已自动抛弃",
                        recovery_hint="请等待模型拉起完毕或节点自愈",
                        details={
                            "service": svc_name,
                            "trace_id": getattr(request.state, "trace_id", "unknown")
                        }
                    ).model_dump()
                )

    response = await call_next(request)
    return response


# 法典 7：禁止 API 无大小限制；有 Content-Length 时拒绝超限请求
MAX_REQUEST_BODY_BYTES = int(os.getenv("MAX_REQUEST_BODY_BYTES", "10485760"))  # 10MB

@app.middleware("http")
async def limit_request_body(request: Request, call_next):
    """请求体大小限制，超限返回 413。"""
    cl = request.headers.get("content-length")
    if cl and request.method in ("POST", "PUT", "PATCH"):
        try:
            size = int(cl)
            if size > MAX_REQUEST_BODY_BYTES:
                return JSONResponse(
                    status_code=413,
                    content=ErrorResponse(
                        code="ZEN-REQ-413",
                        message="Request entity too large",
                        recovery_hint=f"请求体不得超过 {MAX_REQUEST_BODY_BYTES // (1024*1024)} MB",
                        details={
                            "max_bytes": MAX_REQUEST_BODY_BYTES,
                            "trace_id": getattr(request.state, "trace_id", "unknown")
                        },
                    ).model_dump(),
                )
        except ValueError:
            pass
    return await call_next(request)


@app.middleware("http")
async def add_request_id(request: Request, call_next):
    """法典：所有响应携带 X-Request-ID。"""
    rid = request.headers.get("X-Request-ID") or str(uuid.uuid4())
    request.state.request_id = rid
    response = await call_next(request)
    response.headers["X-Request-ID"] = rid
    return response


# -------------------- 统一异常处理（法典 2.1.1 建议7）--------------------
@app.exception_handler(HTTPException)
async def http_handler(request: Request, exc: HTTPException):
    if isinstance(exc.detail, dict) and "code" in exc.detail:
        return JSONResponse(status_code=exc.status_code, content=exc.detail)
    return JSONResponse(
        status_code=exc.status_code,
        content=ErrorResponse(
            code=f"ZEN-HTTP-{exc.status_code}",
            message=str(exc.detail),
            recovery_hint="检查请求参数后重试",
            details={
                "request_id": getattr(request.state, "request_id", ""),
                "trace_id": getattr(request.state, "trace_id", "unknown")
            },
        ).model_dump(),
    )


@app.exception_handler(RequestValidationError)
async def validation_handler(request: Request, exc: RequestValidationError):
    return JSONResponse(
        status_code=422,
        content=ErrorResponse(
            code="ZEN-VAL-422",
            message="请求参数校验失败",
            recovery_hint="请检查请求体格式与必填字段",
            details={
                "errors": exc.errors(),
                "trace_id": getattr(request.state, "trace_id", "unknown")
            },
        ).model_dump(),
    )


@app.exception_handler(Exception)
async def global_handler(request: Request, exc: Exception):
    rid = getattr(request.state, "request_id", "unknown")
    trace_id = getattr(request.state, "trace_id", "unknown")
    logger.exception(f"Unhandled Server Error: {exc}")
    return JSONResponse(
        status_code=500,
        content=ErrorResponse(
            code="ZEN-INT-5000",
            message="服务内部错误",
            recovery_hint="请稍后重试或联系管理员",
            details={"request_id": rid, "trace_id": trace_id},
        ).model_dump(),
    )


