@app.get("/api/v1/capabilities", response_model=Dict[str, CapabilityItem])
async def capabilities(
    request: Request,
    current_user: dict | None = Depends(get_current_user_optional)
):
    """
    法典 2.3.1：返回能力矩阵，供前端 v-for 动态渲染。
    法典 3.2.5：Redis 失联时返回 All-OFF 矩阵并带 X-ZEN70-Bus-Status: not-ready 告警。
    """
    matrix = await get_capabilities_matrix(request)
    bus_ready = getattr(request.state, "bus_ready", True)
    role = current_user.get("role", "family") if current_user else "guest"

    # Role-Based Rendering:
    if role != "admin":
        matrix = {k: v for k, v in matrix.items() if k not in ("容灾备份", "容器启停")}
    if role == "guest":
        matrix = {k: v for k, v in matrix.items() if k in ["ups", "network"]}

    if not bus_ready:
        return JSONResponse(
            content={k: v.model_dump() for k, v in matrix.items()},
            headers={"X-ZEN70-Bus-Status": "not-ready"},
        )
    return matrix


class PingRequest(BaseModel):
    """Ping 请求体：前端每 30s 调用，防 45s 超时 cancel。"""
    connection_id: str = Field(..., description="SSE 连接建立时下发的 ID")


@app.post("/api/v1/stream/ping")
async def stream_ping(body: PingRequest):
    """法典 2.1.1：前端每 30s 调此接口续期，否则 45s 后服务端 cancel SSE。"""
    _sse_last_ping[body.connection_id] = time.time()
    return {"ok": True}


@app.get("/api/v1/stream")
async def stream(request: Request):
    """
    法典 2.1.1：SSE 单向推送。前端每 30s 调 POST /api/v1/stream/ping 续期，
    后端 45s 未收到必须 cancel() 释放 FD，杜绝半开连接耗尽资源。
    """
    if redis is None:
        return JSONResponse(
            status_code=503,
            content=ErrorResponse(
                code="ZEN-SSE-5001",
                message="Redis 不可用，SSE 无法启动",
                recovery_hint="等待总线就绪后重试，禁止盲目轮询",
                details={"trace_id": getattr(request.state, "trace_id", "unknown")},
            ).model_dump(),
        )

    conn_id = str(uuid.uuid4())
    _sse_last_ping[conn_id] = time.time()

    async def event_gen():
        r, pub = None, None
        try:
            r = await _get_redis()
            if r is None:
                yield {"event": "error", "data": '{"code":"ZEN-SSE-5001"}'}
                return
            pub = r.pubsub()
            await pub.subscribe("hardware:events", "switch:events", "board:events")
            yield {"event": "connected", "data": f'{{"connection_id":"{conn_id}"}}'}
            while True:
                # 法典：45s 未收 Ping 必须 cancel
                if time.time() - _sse_last_ping.get(conn_id, 0) > SSE_PING_TIMEOUT:
                    break
                if getattr(request, "is_disconnected", None) and callable(request.is_disconnected):
                    if request.is_disconnected():
                        break
                try:
                    msg = await asyncio.wait_for(
                        pub.get_message(timeout=1.0, ignore_subscribe_messages=True),
                        timeout=2.0,
                    )
                    if msg and msg.get("type") == "message":
                        yield {"event": msg.get("channel", ""), "data": msg.get("data", "{}")}
                    else:
                        matrix = await get_capabilities_matrix(request)
                        yield {"event": "heartbeat", "data": str(matrix)}
                except asyncio.TimeoutError:
                    matrix = await get_capabilities_matrix(request)
                    yield {"event": "heartbeat", "data": str(matrix)}
                except asyncio.CancelledError:
                    break
        finally:
            _sse_last_ping.pop(conn_id, None)
            if pub:
                try:
                    await pub.unsubscribe("hardware:events", "switch:events", "board:events")
                except Exception:
                    pass
            if r:
                try:
                    await r.aclose()
                except Exception:
                    pass

    return EventSourceResponse(
        event_gen(),
        headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
    )


@app.get("/health")
async def health():
    """健康检查。"""
    r = await _get_redis()
    ok = False
    if r:
        try:
            await r.ping()
            ok = True
        except Exception:
            pass
        finally:
            try:
                await r.aclose()
            except Exception:
                pass
    return {"status": "healthy" if ok else "degraded", "redis": "ok" if ok else "error"}


